\begin{lemma}[Postcomposition of a derivation distributes over composition]
  \label{lem:derivation_postcomp_comp}
  \lean{PresheafOfModules.Derivation.postcomp_comp}
  Let $d : R \to M$ be a derivation of presheaves of $\mathcal R$-modules and let $f : M \to N$, $g : N \to P$ be morphisms of presheaves of $\mathcal R$-modules. Then
  \[
    d.\mathrm{postcomp}(f \circ g) \;=\; (d.\mathrm{postcomp}\,f).\mathrm{postcomp}\,g.
  \]
  The proof is by Derivation extensionality on each open: both sides evaluate to $g.\mathrm{app}_U \circ f.\mathrm{app}_U \circ d_U$ at section $b$. This is a Mathlib-shape lemma about $\mathrm{Derivation}'$ that is missing from Mathlib's $\mathrm{PresheafOfModules}/\mathrm{Differentials}/\mathrm{Presheaf.lean}$.
\end{lemma>
